import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import api from '../utils/api';
import Sidebar from '../components/common/Sidebar';
import { DateTimePicker } from '../components/common/DatePicker';
import {
  MATERIAL_DENSITY_G_CM3,
  calculateMaterialEstimates,
  calculatePrintTimeEstimate,
  invalidStlMetadata,
  parseStlFile,
  withMaterialEstimates,
} from '../utils/stlMetadata';

const helperStyle = {
  color: 'var(--text-muted)',
  fontSize: '0.72rem',
  lineHeight: 1.45,
};

const Section = ({ number, title, description, children }) => (
  <section className="card" style={{ marginBottom: '1rem' }}>
    <div style={{ marginBottom: '1rem' }}>
      <h3 style={{ fontSize: '0.82rem', color: 'var(--accent)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '0.25rem' }}>
        {number ? `${number}. ` : ''}{title}
      </h3>
      {description && <p style={helperStyle}>{description}</p>}
    </div>
    {children}
  </section>
);

const Field = ({ label, required, children, span = 1, help }) => (
  <div className="form-group" style={{ gridColumn: span > 1 ? `span ${span}` : undefined, minWidth: 0 }}>
    <label className="form-label" title={help || label}>
      {label}{required && <span style={{ color: 'var(--accent)', marginLeft: '0.2rem' }}>*</span>}
    </label>
    {children}
    {help && <span style={helperStyle}>{help}</span>}
  </div>
);

const fileName = (file) => file?.name || file?.original_name || file?.filename || '';
const fileType = (file) => String(file?.file_type || fileName(file).split('.').pop() || '').toLowerCase();
const isStlFile = (file) => fileType(file) === 'stl' || fileName(file).toLowerCase().endsWith('.stl');

const formatFileSize = (bytes) => {
  const size = Number(bytes || 0);
  if (!Number.isFinite(size) || size <= 0) return '-';
  return `${(size / 1024 / 1024).toFixed(1)} MB`;
};

const formatNumber = (value, digits = 1) => {
  const number = Number(value);
  if (!Number.isFinite(number)) return '-';
  return number.toLocaleString(undefined, { maximumFractionDigits: digits, minimumFractionDigits: digits });
};

const formatDuration = (minutes) => {
  const total = Math.round(Number(minutes || 0));
  if (!Number.isFinite(total) || total <= 0) return null;
  const h = Math.floor(total / 60);
  const m = total % 60;
  return h > 0 ? `${h} h ${m} min` : `${m} min`;
};

const money = (value) => {
  const number = Number(value);
  return Number.isFinite(number) ? `${number.toFixed(2)} EUR` : null;
};

const FIXED_COST = 9.86;

const densityForMaterial = (material = {}) => {
  const candidates = [material.name, material.type, material.material_preference]
    .filter(Boolean)
    .map(value => String(value).toLowerCase());
  const key = Object.keys(MATERIAL_DENSITY_G_CM3).find(name => (
    candidates.some(candidate => candidate === name.toLowerCase() || candidate.includes(name.toLowerCase()))
  ));
  return key ? MATERIAL_DENSITY_G_CM3[key] : null;
};

const parseDimensions = (value) => {
  const numbers = String(value || '').match(/(\d+(?:\.\d+)?)/g)?.map(Number) || [];
  if (numbers.length < 3) return null;
  const [length, width, height] = numbers;
  if (![length, width, height].every(n => Number.isFinite(n) && n > 0)) return null;
  return { length, width, height, volumeMm3: length * width * height };
};

const shouldValidateDimensions = (value) => /x|×|mm|cm|length|width|height/i.test(String(value || ''));

const printerProfileFor = (printer = {}) => ({
  name: printer.name ? `${printer.name}${printer.model ? ` ${printer.model}` : ''}` : 'Default FDM Profile',
  averagePrintSpeedMmS: Number(printer.print_speed || printer.average_print_speed || 60),
  setupFactor: Number(printer.setup_factor || 1.15),
  efficiencyFactor: Number(printer.efficiency_factor || 0.85),
});

const valueBoxStyle = {
  padding: '0.75rem',
  background: 'var(--bg-hover)',
  borderRadius: 6,
  minHeight: 72,
};

const FlashValue = ({ value, children, strong = false }) => {
  const [flash, setFlash] = useState(false);
  const [previous, setPrevious] = useState(value);

  useEffect(() => {
    if (previous !== value) {
      setFlash(true);
      const timer = setTimeout(() => setFlash(false), 900);
      setPrevious(value);
      return () => clearTimeout(timer);
    }
    return undefined;
  }, [previous, value]);

  return (
    <div style={{
      transition: 'background 180ms ease, color 180ms ease',
      background: flash ? 'var(--yellow-dim)' : 'transparent',
      borderRadius: 4,
      padding: '0.1rem 0.2rem',
      margin: '-0.1rem -0.2rem',
      fontWeight: strong ? 800 : 700,
    }}>
      {children || value || '-'}
    </div>
  );
};

const CostBreakdownPanel = ({ estimate, material, printer, validationMessages }) => {
  const unit = material?.unit || 'g';
  return (
    <Section number={null} title="Cost Breakdown">
      {validationMessages.length > 0 && (
        <div className="alert alert-warning" style={{ marginBottom: '1rem' }}>
          {validationMessages[0]}
        </div>
      )}
      <div className="grid-2" style={{ marginBottom: '1rem' }}>
        <div style={valueBoxStyle}>
          <div className="form-label">Selected Material</div>
          <FlashValue value={material?.name}>{material?.name || 'Select material'}</FlashValue>
          <div style={helperStyle}>
            Cost Rate: {material?.cost_per_unit ? `${Number(material.cost_per_unit).toFixed(4)} ${material.currency || 'EUR'}/${unit}` : 'Not configured'}
          </div>
          <div style={helperStyle}>Available Stock: {material ? `${formatNumber(material.available_quantity ?? material.stock_quantity, 1)} ${unit}` : '-'}</div>
          <div style={helperStyle}>Density: {estimate.materialDensity ? `${formatNumber(estimate.materialDensity, 2)} g/cm3` : 'Not available'}</div>
        </div>
        <div style={valueBoxStyle}>
          <div className="form-label">Selected Printer</div>
          <FlashValue value={printer?.name}>{printer?.name || 'Select printer'}</FlashValue>
          <div style={helperStyle}>Cost Rate: {printer?.cost_per_minute ? `${Number(printer.cost_per_minute).toFixed(4)} EUR/min` : 'Not configured'}</div>
          <div style={helperStyle}>Printer Profile: {estimate.printerProfile?.name || '-'}</div>
          <div style={helperStyle}>
            Print Speed: {estimate.printerProfile?.averagePrintSpeedMmS || 60} mm/s · Efficiency {estimate.printerProfile?.efficiencyFactor || 0.85}
          </div>
        </div>
      </div>
      <div className="grid-2">
        {[
          ['Cost Source', estimate.source || '-'],
          ['Quantity', estimate.quantity ? String(estimate.quantity) : '-'],
          ['Weight Per Part', estimate.weightPerPart ? `${formatNumber(estimate.weightPerPart, 1)} ${unit}` : '-'],
          ['Estimated Weight', estimate.weight ? `${formatNumber(estimate.weight, 1)} ${unit}` : '-'],
          ['Material Usage Per Part', estimate.materialUsagePerPart ? `${formatNumber(estimate.materialUsagePerPart, 1)} ${unit}` : '-'],
          ['Required Material', estimate.materialUsage ? `${formatNumber(estimate.materialUsage, 1)} ${unit}` : '-'],
          ['Print Time Per Part', formatDuration(estimate.printTimePerPartMinutes) || '-'],
          ['Estimated Print Time', formatDuration(estimate.printTimeMinutes) || '-'],
          ['Cost Per Part', money(estimate.costPerPart) || '-'],
          ['Material Cost', money(estimate.materialCost) || '-'],
          ['Machine Cost', money(estimate.machineCost) || '-'],
          ['Fixed Cost', money(estimate.fixedCost) || '-'],
          ['Estimated Machine Occupancy', estimate.printTimeMinutes ? `${formatNumber(estimate.printTimeMinutes / 60, 1)} hours` : '-'],
          ['Remaining Stock After Production', estimate.remainingStock !== null && estimate.remainingStock !== undefined ? `${formatNumber(estimate.remainingStock, 1)} ${unit}` : '-'],
          ['Estimated Total Cost', money(estimate.totalCost) || '-'],
        ].map(([label, value]) => (
          <div key={label} style={valueBoxStyle}>
            <div className="form-label">{label}</div>
            <FlashValue value={value} strong={label === 'Estimated Total Cost'}>{value}</FlashValue>
          </div>
        ))}
      </div>
    </Section>
  );
};

const StlAnalysisCard = ({ file, metadata, status }) => {
  const isInvalid = metadata?.parse_status === 'invalid';
  const isLoading = status === 'loading';
  return (
    <div className="card" style={{ padding: '1rem', background: 'var(--bg-secondary)' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', gap: '0.75rem', marginBottom: '0.85rem', alignItems: 'flex-start' }}>
        <div style={{ minWidth: 0 }}>
          <div className="form-label">File Name</div>
          <strong style={{ display: 'block', fontSize: '0.9rem', overflowWrap: 'anywhere' }}>{fileName(file)}</strong>
        </div>
        <span className="badge" style={{ background: isInvalid ? 'var(--red-dim)' : 'var(--green-dim)', color: isInvalid ? 'var(--red)' : 'var(--green)' }}>
          {isInvalid ? 'Invalid STL File' : isLoading ? 'Analyzing' : 'Metadata Generated'}
        </span>
      </div>
      {isInvalid ? (
        <p style={{ ...helperStyle, color: 'var(--red)' }}>{metadata?.error_message || 'Invalid STL File'}</p>
      ) : (
        <div className="grid-2">
          <div><div className="form-label">File Size</div><div>{formatFileSize(file.size || file.file_size)}</div></div>
          <div><div className="form-label">Volume</div><div>{isLoading ? 'Analyzing...' : `${formatNumber(Number(metadata?.volume_mm3) / 1000, 1)} cm³`}</div></div>
          <div><div className="form-label">Dimensions</div><div>{isLoading ? 'Analyzing...' : `${formatNumber(metadata?.bounding_box_x_mm, 1)} x ${formatNumber(metadata?.bounding_box_y_mm, 1)} x ${formatNumber(metadata?.bounding_box_z_mm, 1)} mm`}</div></div>
          <div><div className="form-label">Triangles</div><div>{isLoading ? 'Analyzing...' : Number(metadata?.triangle_count || 0).toLocaleString()}</div></div>
          <div><div className="form-label">Weight Per Part</div><div>{isLoading ? 'Analyzing...' : metadata?.estimated_weight_g ? `${formatNumber(metadata.estimated_weight_g, 1)} g` : 'Select a catalog material'}</div></div>
          <div><div className="form-label">Total Weight</div><div>{isLoading ? 'Analyzing...' : metadata?.estimated_weight_total_g ? `${formatNumber(metadata.estimated_weight_total_g, 1)} g` : 'Select quantity and material'}</div></div>
          <div><div className="form-label">Material Usage Per Part</div><div>{isLoading ? 'Analyzing...' : metadata?.estimated_material_usage_g ? `${formatNumber(metadata.estimated_material_usage_g, 1)} g` : 'Select material and infill'}</div></div>
          <div><div className="form-label">Total Material Usage</div><div>{isLoading ? 'Analyzing...' : metadata?.estimated_material_usage_total_g ? `${formatNumber(metadata.estimated_material_usage_total_g, 1)} g` : 'Select material and infill'}</div></div>
          <div><div className="form-label">Print Time Per Part</div><div>{isLoading ? 'Analyzing...' : formatDuration(metadata?.estimated_print_time_minutes) || 'Select layer height'}</div></div>
          <div><div className="form-label">Total Print Time</div><div>{isLoading ? 'Analyzing...' : formatDuration(metadata?.estimated_print_time_total_minutes) || 'Select layer height'}</div></div>
          <div><div className="form-label">Material Cost</div><div>{isLoading ? 'Analyzing...' : money(metadata?.stl_material_cost) || 'Not available'}</div></div>
          <div><div className="form-label">Time Cost</div><div>{isLoading ? 'Analyzing...' : money(metadata?.stl_time_cost) || 'Not available'}</div></div>
          <div><div className="form-label">Fixed Cost</div><div>{isLoading ? 'Analyzing...' : money(metadata?.stl_fixed_cost) || 'Not available'}</div></div>
          <div><div className="form-label">Estimated Total Cost</div><div style={{ fontWeight: 700 }}>{isLoading ? 'Analyzing...' : money(metadata?.stl_estimated_total_cost) || 'Not available'}</div></div>
        </div>
      )}
    </div>
  );
};

export default function RequestFormPage() {
  const { id } = useParams();
  const isEdit = Boolean(id);
  const navigate = useNavigate();
  const [categories, setCategories] = useState([]);
  const [sites, setSites] = useState([]);
  const [materials, setMaterials] = useState([]);
  const [printers, setPrinters] = useState([]);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');
  const [files, setFiles] = useState([]);
  const [existingFiles, setExistingFiles] = useState([]);
  const [stlAnalyses, setStlAnalyses] = useState({});
  const [requestStatus, setRequestStatus] = useState('draft');

  const [form, setForm] = useState({
    title: '', purpose: '', part_description: '', quantity: 1,
    functional_requirement: '', visual_requirement: '', category_id: '',
    criticality: 'normal', use_environment: '',
    dimensions: '', scale: '', tolerance: '', surface_finish: '',
    strength_requirement: '', color_preference: '', material_preference: '',
    infill_percentage: '', layer_height: '', orientation: '',
    priority: 'normal', priority_reason: '', requested_due_date: '',
    project_reference: '', customer_reference: '', site_id: '',
    material_id: '', printer_id: '',
  });

  useEffect(() => {
    api.get('/categories').then(r => setCategories(r.data));
    api.get('/materials').then(r => setMaterials(r.data || []));
    api.get('/printers').then(r => setPrinters(r.data || []));
    api.get('/sites').then(r => {
      setSites(r.data);
      if (!isEdit && r.data.length === 1) setForm(f => ({ ...f, site_id: r.data[0].id }));
    });
    if (isEdit) {
      setLoading(true);
      api.get(`/requests/${id}`).then(r => {
        const d = r.data;
        setRequestStatus(d.status || 'draft');
        const loadedMaterial = d.material_preference || '';
        setForm({
          title: d.title || '', purpose: d.purpose || '',
          part_description: d.part_description || '', quantity: d.quantity || 1,
          functional_requirement: d.functional_requirement || '',
          visual_requirement: d.visual_requirement || '',
          category_id: d.category_id || '', criticality: d.criticality || 'normal',
          use_environment: d.use_environment || '',
          dimensions: d.dimensions || '', scale: d.scale || '',
          tolerance: d.tolerance || '', surface_finish: d.surface_finish || '',
          strength_requirement: d.strength_requirement || '',
          color_preference: d.color_preference || '',
          material_preference: loadedMaterial,
          infill_percentage: d.infill_percentage || '',
          layer_height: d.layer_height || '', orientation: d.orientation || '',
          priority: d.priority || 'normal', priority_reason: d.priority_reason || '',
          requested_due_date: d.requested_due_date ? String(d.requested_due_date).slice(0, 16) : '',
          project_reference: d.project_reference || '',
          customer_reference: d.customer_reference || '',
          site_id: d.site_id || '',
          material_id: d.material_id || '',
          printer_id: d.printer_id || '',
        });
        setExistingFiles(d.attachments || []);
        setLoading(false);
      });
    }
  }, [id, isEdit]);

  const set = (key, val) => setForm(f => ({ ...f, [key]: val }));
  const dimensionParts = parseDimensions(form.dimensions);
  const setDimensionPart = (part, value) => {
    const current = parseDimensions(form.dimensions) || { length: '', width: '', height: '' };
    const next = { ...current, [part]: value };
    const hasAny = [next.length, next.width, next.height].some(v => v !== '');
    set('dimensions', hasAny ? `${next.length || ''} x ${next.width || ''} x ${next.height || ''} mm` : '');
  };

  const selectedMaterial = (materials || []).find(material => material.id === form.material_id)
    || (materials || []).find(material => material.name === form.material_preference)
    || null;
  const selectedPrinter = (printers || []).find(printer => printer.id === form.printer_id) || null;
  const selectedMaterialExists = !form.material_preference || (materials || []).some(material => material.name === form.material_preference);
  const quantity = Math.max(1, Number(form.quantity || 1));
  const selectedMaterialName = selectedMaterial?.name || form.material_preference;
  const selectedPrinterProfile = printerProfileFor(selectedPrinter || {});
  const hasStlFiles = files.some(isStlFile) || existingFiles.some(isStlFile);
  const stlAnalysisItems = [
    ...files.filter(isStlFile).map((file, index) => ({
      key: `new-${file.name}-${file.size}-${index}`,
      file,
      metadata: withMaterialEstimates(
        stlAnalyses[`new-${file.name}-${file.size}-${file.lastModified}`],
        selectedMaterialName,
        form.infill_percentage,
        form.layer_height,
        {
          quantity,
          materialCostPerUnit: selectedMaterial?.cost_per_unit,
          printerCostPerMinute: selectedPrinter?.cost_per_minute,
          printerProfile: selectedPrinterProfile,
        }
      ),
      status: stlAnalyses[`new-${file.name}-${file.size}-${file.lastModified}`] ? 'done' : 'loading',
    })),
    ...existingFiles.filter(isStlFile).map(file => ({
      key: `existing-${file.id}`,
      file,
      metadata: withMaterialEstimates(
        file.stl_metadata || invalidStlMetadata('Metadata has not been generated for this STL file yet.'),
        selectedMaterialName,
        form.infill_percentage,
        form.layer_height,
        {
          quantity,
          materialCostPerUnit: selectedMaterial?.cost_per_unit,
          printerCostPerMinute: selectedPrinter?.cost_per_minute,
          printerProfile: selectedPrinterProfile,
        }
      ),
      status: 'done',
    })),
  ];
  const primaryStlEstimate = stlAnalysisItems
    .map(item => item.metadata)
    .find(metadata => metadata?.parse_status !== 'invalid' && metadata?.stl_estimated_total_cost);
  const dimensionEstimate = (() => {
    const parsed = parseDimensions(form.dimensions);
    if (!parsed || primaryStlEstimate) return null;
    const density = densityForMaterial(selectedMaterial || { name: selectedMaterialName });
    const materialEstimate = calculateMaterialEstimates({
      volumeMm3: parsed.volumeMm3,
      materialPreference: selectedMaterialName,
      infillPercentage: form.infill_percentage,
    });
    const printEstimate = calculatePrintTimeEstimate({
      volumeMm3: parsed.volumeMm3,
      estimatedMaterialUsageG: materialEstimate.estimated_material_usage_g,
      materialDensityGcm3: materialEstimate.material_density_g_cm3 || density,
      layerHeight: form.layer_height,
      infillPercentage: form.infill_percentage,
      printerProfile: selectedPrinterProfile,
    });
    const weight = Number(materialEstimate.estimated_weight_g);
    const usage = Number(materialEstimate.estimated_material_usage_g);
    const minutes = Number(printEstimate.estimated_print_time_minutes);
    return {
      source: 'Dimension Based',
      quantity,
      weightPerPart: Number.isFinite(weight) ? weight : null,
      weight: Number.isFinite(weight) ? weight * quantity : null,
      materialUsagePerPart: Number.isFinite(usage) ? usage : null,
      materialUsage: Number.isFinite(usage) ? usage * quantity : null,
      printTimePerPartMinutes: Number.isFinite(minutes) ? minutes : null,
      printTimeMinutes: Number.isFinite(minutes) ? minutes * quantity : null,
      materialDensity: materialEstimate.material_density_g_cm3 || density,
      printerProfile: selectedPrinterProfile,
    };
  })();
  const liveEstimate = (() => {
    const base = primaryStlEstimate ? {
      source: 'STL Based',
      quantity,
      weightPerPart: primaryStlEstimate.estimated_weight_g,
      weight: primaryStlEstimate.estimated_weight_total_g,
      materialUsagePerPart: primaryStlEstimate.estimated_material_usage_g,
      materialUsage: primaryStlEstimate.estimated_material_usage_total_g,
      printTimePerPartMinutes: primaryStlEstimate.estimated_print_time_minutes,
      printTimeMinutes: primaryStlEstimate.estimated_print_time_total_minutes,
      materialCostPerPart: primaryStlEstimate.stl_material_cost && quantity ? Number(primaryStlEstimate.stl_material_cost) / quantity : null,
      machineCostPerPart: primaryStlEstimate.stl_time_cost && quantity ? Number(primaryStlEstimate.stl_time_cost) / quantity : null,
      materialCost: primaryStlEstimate.stl_material_cost,
      machineCost: primaryStlEstimate.stl_time_cost,
      fixedCost: primaryStlEstimate.stl_fixed_cost,
      totalCost: primaryStlEstimate.stl_estimated_total_cost,
      materialDensity: primaryStlEstimate.material_density_g_cm3,
      printerProfile: selectedPrinterProfile,
    } : dimensionEstimate;
    if (!base) return {
      source: null,
      weight: null,
      materialUsage: null,
      printTimeMinutes: null,
      materialCost: null,
      machineCost: null,
      fixedCost: FIXED_COST,
      totalCost: null,
      quantity,
      weightPerPart: null,
      materialUsagePerPart: null,
      printTimePerPartMinutes: null,
      materialDensity: densityForMaterial(selectedMaterial || { name: selectedMaterialName }),
      printerProfile: selectedPrinterProfile,
      remainingStock: null,
    };
    const materialCost = Number.isFinite(Number(base.materialCost))
      ? Number(base.materialCost)
      : Number.isFinite(Number(base.materialUsage)) && Number.isFinite(Number(selectedMaterial?.cost_per_unit))
        ? Number(base.materialUsage) * Number(selectedMaterial.cost_per_unit)
        : null;
    const machineCost = Number.isFinite(Number(base.machineCost))
      ? Number(base.machineCost)
      : Number.isFinite(Number(base.printTimeMinutes)) && Number.isFinite(Number(selectedPrinter?.cost_per_minute))
        ? Number(base.printTimeMinutes) * Number(selectedPrinter.cost_per_minute)
        : null;
    const totalCost = Number.isFinite(Number(materialCost)) && Number.isFinite(Number(machineCost))
      ? materialCost + machineCost + FIXED_COST
      : Number(base.totalCost);
    const materialCostPerPart = Number.isFinite(Number(base.materialCostPerPart))
      ? Number(base.materialCostPerPart)
      : Number.isFinite(Number(base.materialUsagePerPart)) && Number.isFinite(Number(selectedMaterial?.cost_per_unit))
        ? Number(base.materialUsagePerPart) * Number(selectedMaterial.cost_per_unit)
        : null;
    const machineCostPerPart = Number.isFinite(Number(base.machineCostPerPart))
      ? Number(base.machineCostPerPart)
      : Number.isFinite(Number(base.printTimePerPartMinutes)) && Number.isFinite(Number(selectedPrinter?.cost_per_minute))
        ? Number(base.printTimePerPartMinutes) * Number(selectedPrinter.cost_per_minute)
        : null;
    const available = Number(selectedMaterial?.available_quantity ?? selectedMaterial?.stock_quantity);
    return {
      ...base,
      quantity,
      costPerPart: Number.isFinite(materialCostPerPart) && Number.isFinite(machineCostPerPart)
        ? materialCostPerPart + machineCostPerPart
        : null,
      materialCost,
      machineCost,
      fixedCost: FIXED_COST,
      totalCost: Number.isFinite(totalCost) ? totalCost : null,
      remainingStock: Number.isFinite(available) && Number.isFinite(Number(base.materialUsage))
        ? available - Number(base.materialUsage)
        : null,
    };
  })();
  const liveValidationMessages = [
    quantity <= 0 ? 'Quantity must be greater than zero.' : null,
    form.dimensions && shouldValidateDimensions(form.dimensions) && !parseDimensions(form.dimensions) ? 'Dimensions must include valid length, width, and height values.' : null,
    (selectedMaterialName || hasStlFiles || form.dimensions) && !selectedMaterial ? 'Select a catalog material to calculate material cost.' : null,
    (hasStlFiles || form.dimensions || selectedPrinter) && !selectedPrinter ? 'Select a printer to calculate machine cost.' : null,
    selectedMaterial && !Number.isFinite(Number(selectedMaterial.cost_per_unit)) ? 'Material cost rate is missing in Materials Administration.' : null,
    selectedPrinter && !Number.isFinite(Number(selectedPrinter.cost_per_minute)) ? 'Printer cost rate is missing in Printers Administration.' : null,
  ].filter(Boolean);

  const analyzeStlFiles = (newFiles) => {
    newFiles.filter(isStlFile).forEach(file => {
      const key = `new-${file.name}-${file.size}-${file.lastModified}`;
      setStlAnalyses(prev => ({ ...prev, [key]: null }));
      parseStlFile(file)
        .then(metadata => setStlAnalyses(prev => ({ ...prev, [key]: metadata })))
        .catch(err => setStlAnalyses(prev => ({ ...prev, [key]: invalidStlMetadata(err.message || 'Invalid STL File') })));
    });
  };

  const validateForm = () => {
    if (!form.title.trim()) return 'Title is required';
    if (!form.site_id) return 'Site is required';
    if (!Number.isFinite(Number(form.quantity)) || Number(form.quantity) <= 0) {
      return 'Quantity must be greater than zero.';
    }
    if (form.dimensions && shouldValidateDimensions(form.dimensions) && !parseDimensions(form.dimensions)) {
      return 'Dimensions must include valid length, width, and height values.';
    }
    const wantsCostEstimate = hasStlFiles || Boolean(parseDimensions(form.dimensions));
    if (wantsCostEstimate && !selectedMaterial) {
      return 'Select a catalog material to calculate material cost.';
    }
    if (wantsCostEstimate && !selectedPrinter) {
      return 'Select a printer to calculate machine cost.';
    }

    if (form.infill_percentage !== '') {
      const infill = Number(form.infill_percentage);
      if (!Number.isFinite(infill) || infill < 0 || infill > 100) {
        return 'Infill must be between 0% and 100%.';
      }
    }

    if (form.layer_height !== '') {
      const layerHeight = Number(form.layer_height);
      if (!Number.isFinite(layerHeight) || layerHeight < 0.05 || layerHeight > 1) {
        return 'Layer height must be between 0.05 mm and 1.00 mm.';
      }
    }

    return '';
  };

  const handleSubmit = async (action) => {
    const validationError = validateForm();
    if (validationError) {
      setError(validationError);
      return;
    }

    setSaving(true);
    setError('');
    try {
      let requestId = id;
      const payload = {
        ...form,
        material_id: form.material_id || undefined,
        printer_id: form.printer_id || undefined,
        estimated_printing_time: liveEstimate.printTimeMinutes || undefined,
        material_reserved_qty: liveEstimate.materialUsage || undefined,
        estimated_cost: liveEstimate.totalCost || undefined,
        price_per_kg: selectedMaterial?.cost_per_unit ? Number(selectedMaterial.cost_per_unit) * 1000 : undefined,
      };
      if (isEdit) {
        await api.put(`/requests/${id}`, payload);
      } else {
        const res = await api.post('/requests', payload);
        requestId = res.data.id;
      }

      if (files.length > 0) {
        const fd = new FormData();
        files.forEach(f => fd.append('files', f));
        await api.post(`/requests/${requestId}/files`, fd, {
          headers: { 'Content-Type': 'multipart/form-data' },
        });
      }

      if (action === 'submit' || action === 'resubmit') {
        const comment = action === 'resubmit'
          ? 'Request updated and resubmitted after information correction'
          : 'Request submitted by requester';
        await api.patch(`/requests/${requestId}/status`, { status: 'submitted', comment });
      }

      navigate(`/requests/${requestId}`);
    } catch (err) {
      setError(err.response?.data?.error || 'Save failed');
    } finally {
      setSaving(false);
    }
  };

  if (loading) return (
    <div className="page"><Sidebar />
      <div className="main-content" style={{ display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <span className="spinner" style={{ width: 32, height: 32 }} />
      </div>
    </div>
  );

  return (
    <div className="page">
      <Sidebar />
      <div className="main-content">
        <div className="page-header">
          <div>
            <h1 style={{ fontSize: '1.3rem', fontFamily: 'var(--font-heading)' }}>
              {isEdit ? 'Edit Request' : 'New 3D Print Request'}
            </h1>
            <p style={{ color: 'var(--text-muted)', fontSize: '0.8rem', marginTop: '0.2rem' }}>
              Fill in the required information about your 3D printing need
            </p>
          </div>
          <button className="btn btn-ghost" onClick={() => navigate(-1)}>Cancel</button>
        </div>

        <div className="page-body" style={{ maxWidth: 960 }}>
          {error && <div className="alert alert-error" style={{ marginBottom: '1rem' }}>{error}</div>}

          <Section number="1" title="Request Identification">
            <div className="grid-2">
              <Field label="Title" required span={2} help="Use a clear name that planning and production can recognize quickly.">
                <input className="form-input" value={form.title} onChange={e => set('title', e.target.value)} placeholder="Descriptive title of the part or need" />
              </Field>
              <Field label="Project / Reference">
                <input className="form-input" value={form.project_reference} onChange={e => set('project_reference', e.target.value)} placeholder="Project code or name" />
              </Field>
              <Field label="Customer Reference">
                <input className="form-input" value={form.customer_reference} onChange={e => set('customer_reference', e.target.value)} placeholder="Customer or order reference" />
              </Field>
              <Field label="Site" required>
                <select className="form-select" value={form.site_id} onChange={e => set('site_id', e.target.value)}>
                  <option value="">Select site</option>
                  {sites.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                </select>
              </Field>
              <Field label="Category">
                <select className="form-select" value={form.category_id} onChange={e => set('category_id', e.target.value)}>
                  <option value="">Select category</option>
                  {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
              </Field>
              <Field label="Quantity" required>
                <input type="number" min="1" className="form-input" value={form.quantity} onChange={e => set('quantity', e.target.value)} />
              </Field>
              <Field label="Criticality">
                <select className="form-select" value={form.criticality} onChange={e => set('criticality', e.target.value)}>
                  <option value="low">Low - Cosmetic / non-functional</option>
                  <option value="normal">Normal - Standard functional part</option>
                  <option value="high">High - Production-critical</option>
                  <option value="urgent">Urgent - Line stoppage risk</option>
                </select>
              </Field>
            </div>
          </Section>

          <Section number="2" title="Part Requirements" description="Describe what the part must do and where it will be used.">
            <div className="grid-2">
              <Field label="Purpose" span={2} help="Why is this part needed? What problem does it solve?">
                <textarea className="form-textarea" value={form.purpose} onChange={e => set('purpose', e.target.value)} placeholder="Replacement part, prototype validation, fixture, tooling aid..." />
              </Field>
              <Field label="Part Description" span={2}>
                <textarea className="form-textarea" value={form.part_description} onChange={e => set('part_description', e.target.value)} placeholder="Describe the part: shape, features, assembly context..." />
              </Field>
              <Field label="Functional Requirements" span={2} help="Mention load, fit, assembly, temperature, chemicals, or moving interfaces.">
                <textarea className="form-textarea" value={form.functional_requirement} onChange={e => set('functional_requirement', e.target.value)} placeholder="Load bearing, snap-fit, heat resistance, chemical exposure..." />
              </Field>
              <Field label="Strength Requirement">
                <input className="form-input" value={form.strength_requirement} onChange={e => set('strength_requirement', e.target.value)} placeholder="Structural, light-duty, display only..." />
              </Field>
              <Field label="Expected Use Environment">
                <input className="form-input" value={form.use_environment} onChange={e => set('use_environment', e.target.value)} placeholder="Indoor, UV exposure, high temperature..." />
              </Field>
            </div>
          </Section>

          <Section number="3" title="Visual Requirements">
            <div className="grid-2">
              <Field label="Surface Finish">
                <input className="form-input" value={form.surface_finish} onChange={e => set('surface_finish', e.target.value)} placeholder="As-printed, sanded, painted..." />
              </Field>
              <Field label="Color Preference">
                <input className="form-input" value={form.color_preference} onChange={e => set('color_preference', e.target.value)} placeholder="Black, RAL 7016, match drawing..." />
              </Field>
              <Field label="Visual / Aesthetic Requirements" span={2}>
                <textarea className="form-textarea" value={form.visual_requirement} onChange={e => set('visual_requirement', e.target.value)} placeholder="Appearance, surface quality, visible faces, color matching..." style={{ minHeight: 70 }} />
              </Field>
            </div>
          </Section>

          <Section number="4" title="Manufacturing Preferences" description="These values help prepare future automatic estimation while staying compatible with the current request workflow.">
            <div className="grid-2">
              <Field label="Scale / Scaling Factor">
                <input className="form-input" value={form.scale} onChange={e => set('scale', e.target.value)} placeholder="1:1, 1:2, or 150%" />
              </Field>
              <Field label="Length (mm)">
                <input type="number" min="0.01" step="0.1" className="form-input" value={dimensionParts?.length || ''} onChange={e => setDimensionPart('length', e.target.value)} placeholder="120" />
              </Field>
              <Field label="Width (mm)">
                <input type="number" min="0.01" step="0.1" className="form-input" value={dimensionParts?.width || ''} onChange={e => setDimensionPart('width', e.target.value)} placeholder="80" />
              </Field>
              <Field label="Height (mm)">
                <input type="number" min="0.01" step="0.1" className="form-input" value={dimensionParts?.height || ''} onChange={e => setDimensionPart('height', e.target.value)} placeholder="40" />
              </Field>
              <Field label="Tolerance Requirements">
                <input className="form-input" value={form.tolerance} onChange={e => set('tolerance', e.target.value)} placeholder="+/-0.2 mm, tight fit, press fit..." />
              </Field>
              <Field label="Material Preference" help="Loads cost, density, and stock from Materials Administration.">
                <select
                  className="form-select"
                  value={form.material_id || ''}
                  onChange={e => {
                    const material = materials.find(item => item.id === e.target.value);
                    setForm(current => ({
                      ...current,
                      material_id: e.target.value,
                      material_preference: material?.name || '',
                    }));
                  }}
                >
                  <option value="">Select material</option>
                  {!selectedMaterialExists && (
                    <option value="">{form.material_preference}</option>
                  )}
                  {(materials || []).map(material => (
                    <option key={material.id} value={material.id}>
                      {material.name}{material.type ? ` - ${material.type}` : ''}
                    </option>
                  ))}
                </select>
              </Field>
              <Field label="Preferred Printer" help="Loads configured machine cost and profile for live estimation.">
                <select className="form-select" value={form.printer_id || ''} onChange={e => set('printer_id', e.target.value)}>
                  <option value="">No Preference</option>
                  {(printers || []).map(printer => (
                    <option key={printer.id || printer.name} value={printer.id}>
                      {printer.name}{printer.model ? ` - ${printer.model}` : ''}
                    </option>
                  ))}
                </select>
              </Field>
              <Field label="Infill % (if known)" help="Optional. Must be between 0 and 100.">
                <input type="number" min="0" max="100" className="form-input" value={form.infill_percentage} onChange={e => set('infill_percentage', e.target.value)} placeholder="20" />
              </Field>
              <Field label="Layer Height (mm)" help="Optional. Must be between 0.05 mm and 1.00 mm.">
                <input type="number" step="0.05" min="0.05" max="1" className="form-input" value={form.layer_height} onChange={e => set('layer_height', e.target.value)} placeholder="0.20" />
              </Field>
              <Field label="Preferred Orientation" help="Optional printing orientation hint for the technician.">
                <input className="form-input" value={form.orientation} onChange={e => set('orientation', e.target.value)} placeholder="Flat on bed, upright, angled..." />
              </Field>
            </div>
          </Section>

          <CostBreakdownPanel
            estimate={liveEstimate}
            material={selectedMaterial}
            printer={selectedPrinter}
            validationMessages={liveValidationMessages}
          />

          <Section number="5" title="Attachments" description="Supported: STL, STEP, OBJ, 3MF, DWG, DXF, PDF, PNG, JPG.">
            <div style={{ marginBottom: '1rem' }}>
              <input
                type="file"
                multiple
                accept=".stl,.step,.stp,.obj,.3mf,.cad,.pdf,.png,.jpg,.jpeg,.dwg,.dxf,.zip"
                onChange={e => {
                  const newFiles = Array.from(e.target.files);
                  analyzeStlFiles(newFiles);
                  setFiles(prev => {
                    const existing = new Set(prev.map(f => f.name + f.size));
                    const added = newFiles.filter(f => !existing.has(f.name + f.size));
                    return [...prev, ...added];
                  });
                  e.target.value = '';
                }}
                style={{ display: 'none' }}
                id="file-input"
              />
              <label htmlFor="file-input" className="btn btn-secondary" style={{ cursor: 'pointer' }} title="Attach STL, STEP, OBJ, 3MF, DWG, DXF, PDF, PNG, or JPG files">
                <svg width="14" height="14" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
                  <path d="M21.44 11.05l-9.19 9.19a6 6 0 01-8.49-8.49l9.19-9.19a4 4 0 015.66 5.66l-9.2 9.19a2 2 0 01-2.83-2.83l8.49-8.48" />
                </svg>
                Choose files
              </label>
              {files.length > 0 && (
                <div style={{ marginTop: '0.75rem', display: 'flex', flexDirection: 'column', gap: '0.35rem' }}>
                  <p style={{ fontSize: '0.72rem', color: 'var(--text-muted)', marginBottom: '0.25rem' }}>
                    {files.length} file{files.length !== 1 ? 's' : ''} selected
                  </p>
                  {files.map((f, i) => (
                    <div key={`${f.name}-${f.size}-${i}`} style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', display: 'flex', alignItems: 'center', gap: '0.5rem', padding: '0.35rem 0.6rem', background: 'var(--bg-hover)', borderRadius: 6 }}>
                      <span style={{ color: 'var(--green)' }}>OK</span>
                      <span style={{ flex: 1, minWidth: 0, overflowWrap: 'anywhere' }}>{f.name}</span>
                      <span style={{ color: 'var(--text-muted)', fontSize: '0.72rem' }}>({(f.size / 1024 / 1024).toFixed(1)} MB)</span>
                      <button
                        type="button"
                        onClick={() => setFiles(prev => prev.filter((_, idx) => idx !== i))}
                        style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--red)', fontSize: 16, lineHeight: 1, padding: '0 2px' }}
                        title="Remove file"
                      >x</button>
                    </div>
                  ))}
                </div>
              )}
            </div>
            {existingFiles.length > 0 && (
              <div>
                <p style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginBottom: '0.5rem', textTransform: 'uppercase', letterSpacing: '0.05em' }}>Existing files</p>
                {existingFiles.map(f => (
                  <div key={f.id} style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.3rem' }}>
                    <span style={{ color: 'var(--blue)' }}>File</span>
                    <span style={{ overflowWrap: 'anywhere' }}>{f.original_name}</span>
                  </div>
                ))}
              </div>
            )}
          </Section>

          {hasStlFiles && (
            <Section number="6" title="STL Analysis" description="Read-only preparation area for the future STL Intelligence module.">
              <div style={{ display: 'flex', flexDirection: 'column', gap: '0.85rem' }}>
                {stlAnalysisItems.map(item => (
                  <StlAnalysisCard key={item.key} file={item.file} metadata={item.metadata} status={item.status} />
                ))}
              </div>
            </Section>
          )}

          <Section number={hasStlFiles ? '7' : '6'} title="Planning & Priority">
            <div className="grid-2">
              <Field label="Priority" required>
                <select className="form-select" value={form.priority} onChange={e => set('priority', e.target.value)}>
                  <option value="low">Low</option>
                  <option value="normal">Normal</option>
                  <option value="high">High</option>
                  <option value="critical">Critical</option>
                </select>
              </Field>
              <Field label="Requested Due Date">
                <DateTimePicker value={form.requested_due_date} onChange={v => set('requested_due_date', v)} placeholder="Select due date and time" />
              </Field>
              <Field label="Reason for Priority / Urgency" span={2}>
                <textarea className="form-textarea" value={form.priority_reason} onChange={e => set('priority_reason', e.target.value)} placeholder="If high or critical, explain why..." style={{ minHeight: 60 }} />
              </Field>
            </div>
          </Section>

          {isEdit && requestStatus === 'more_info_required' && (
            <div className="alert alert-warning" style={{ marginBottom: '1rem' }}>
              <strong>Information Required</strong> - The coordinator has requested corrections.
              Update the necessary fields and click <strong>Save &amp; Resubmit</strong>.
            </div>
          )}

          <div style={{ display: 'flex', gap: '0.75rem', justifyContent: 'flex-end', paddingTop: '1rem', borderTop: '1px solid var(--border)', flexWrap: 'wrap' }}>
            <button className="btn btn-ghost" onClick={() => navigate(-1)} disabled={saving}>Cancel</button>
            {requestStatus !== 'more_info_required' && (
              <button className="btn btn-secondary" onClick={() => handleSubmit('save')} disabled={saving}>
                {saving ? <span className="spinner" style={{ width: 14, height: 14 }} /> : null}
                Save as Draft
              </button>
            )}
            {requestStatus === 'more_info_required' ? (
              <button className="btn btn-primary" onClick={() => handleSubmit('resubmit')} disabled={saving} style={{ background: 'var(--yellow)', color: '#000' }}>
                {saving ? <span className="spinner" style={{ width: 14, height: 14 }} /> : null}
                Save &amp; Resubmit
              </button>
            ) : (
              <button className="btn btn-primary" onClick={() => handleSubmit('submit')} disabled={saving}>
                {saving ? <span className="spinner" style={{ width: 14, height: 14 }} /> : null}
                Save &amp; Submit
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
